+import { $internal } from '../common';
+import type { Entity } from '../entity/types';
+import { isRelationPair } from '../relation/utils/is-relation';
+import type { Schema } from '../storage';
+import type { World } from '../world';
+import { addTrait, getTrait, hasTrait, removeTrait, setTrait } from './trait';
+import type { ConfigurableTrait, Trait, TraitRecord } from './types';
+
+export const $aspect = Symbol('aspect');
+
+export type Aspect<T extends readonly Trait[] = readonly Trait[]> = {
+    readonly [$aspect]: true;
+    readonly id: number;
+    readonly traits: T;
+    readonly schema: Record<string, unknown>;
+};
+
+let aspectId = 0;
+
+export function isAspect(value: unknown): value is Aspect {
+    return !!(value as Aspect | undefined)?.[$aspect];
+}
+
+export function createAspect<T extends readonly [Trait | Aspect, Trait | Aspect, ...(Trait | Aspect)[]]>(
+    ...inputs: T
+): Aspect<readonly Trait[]> {
+    const traits: Trait[] = [];
+    for (const input of inputs) {
+        if (isAspect(input)) traits.push(...input.traits);
+        else traits.push(input);
+    }
+
+    const schema: Record<string, unknown> = {};
+    const fields = new Set<string>();
+    for (const trait of traits) {
+        if (trait[$internal].relation) {
+            throw new Error('Koota: Relations cannot be constituents of an aspect.');
+        }
+        for (const key of Object.keys(trait.schema as Schema)) {
+            if (fields.has(key)) {
+                throw new Error(`Koota: Aspect constituents overlap on field "${key}".`);
+            }
+            fields.add(key);
+            schema[key] = (trait.schema as Record<string, unknown>)[key];
+        }
+    }
+
+    return Object.freeze({ [$aspect]: true as const, id: aspectId++, traits: Object.freeze(traits), schema: Object.freeze(schema) });
+}
+
+export function hasAspect(world: World, entity: Entity, aspect: Aspect): boolean {
+    return aspect.traits.every((trait) => hasTrait(world, entity, trait));
+}
+
+export function getAspect(world: World, entity: Entity, aspect: Aspect): Record<string, unknown> | undefined {
+    if (!hasAspect(world, entity, aspect)) return undefined;
+    const result: Record<string, unknown> = {};
+    for (const trait of aspect.traits) Object.assign(result, getTrait(world, entity, trait));
+    return result;
+}
+
+function valuesFor(trait: Trait, value: Record<string, unknown>) {
+    const result: Record<string, unknown> = {};
+    for (const key of Object.keys(trait.schema)) if (key in value) result[key] = value[key];
+    return result;
+}
+
+export function setAspect(world: World, entity: Entity, aspect: Aspect, value: Record<string, unknown>, changed = true) {
+    for (const trait of aspect.traits) setTrait(world, entity, trait, valuesFor(trait, value), changed);
+}
+
+export function addAspect(world: World, entity: Entity, aspect: Aspect, value?: Record<string, unknown>) {
+    for (const trait of aspect.traits) {
+        if (!hasTrait(world, entity, trait)) {
+            const fields = value ? valuesFor(trait, value) : undefined;
+            addTrait(world, entity, fields && Object.keys(fields).length ? ([trait, fields] as ConfigurableTrait) : trait);
+        }
+    }
+}
+
+export function removeAspect(world: World, entity: Entity, aspect: Aspect) {
+    removeTrait(world, entity, ...aspect.traits);
+}
+
+export function aspectTraits(input: Trait | Aspect): Trait[] {
+    return isAspect(input) ? [...input.traits] : [input];
+}
